	"log"
	"os"
	"path/filepath"

	"github.com/google/uuid"
	"github.com/spf13/cobra"
)

var rootDir = ".photobox"
var metadataDir = filepath.Join(rootDir, "metadata")

type PhotoMetadata struct {
	Date        string `json:"date"`
	Category    string `json:"category"`
	Description string `json:"description"`
	FilePath    string `json:"file_path"`
}

var rootCmd = &cobra.Command{
	Use:   "photobox",
	Short: "Personal digital photography archive manager",
}

var initCmd = &cobra.Command{
	Use:   "init",
	Short: "Initialize archive structure",
	Run: func(cmd *cobra.Command, args []string) {
		if err := os.MkdirAll(metadataDir, 0755); err != nil {
			log.Fatal(err)
		}
		fmt.Println("Archive initialized")
	},
}

var addCmd = &cobra.Command{
	Use:   "add",
	Short: "Add new photo entry",
	Run: func(cmd *cobra.Command, args []string) {
		date, _ := cmd.Flags().GetString("date")
		category, _ := cmd.Flags().GetString("category")
		desc, _ := cmd.Flags().GetString("desc")

		id := uuid.New()
		metaPath := filepath.Join(metadataDir, id.String()+".json")

		photo := PhotoMetadata{
			Date:        date,
			Category:    category,
			Description: desc,
			FilePath:    metaPath,
		}

		file, err := os.Create(metaPath)
		if err != nil {
			log.Fatal(err)
		}
		defer file.Close()

		encoder := json.NewEncoder(file)
		if err := encoder.Encode(photo); err != nil {
			log.Fatal(err)
		}
		fmt.Println("Photo entry added")
	},
}

var reportCmd = &cobra.Command{
	Use:   "report",
	Short: "Generate summary report",
	Run: func(cmd *cobra.Command, args []string) {
		entries, err := os.ReadDir(metadataDir)
		if err != nil {
			log.Fatal(err)
		}

		categories := make(map[string][]string)

		for _, entry := range entries {
			path := filepath.Join(metadataDir, entry.Name())
			file, err := os.Open(path)
			if err != nil {
				log.Fatal(err)
			}

			var meta PhotoMetadata
			decoder := json.NewDecoder(file)
			if err := decoder.Decode(&meta); err != nil {
				file.Close()
				log.Fatal(err)
			}
			file.Close()

			categories[meta.Category] = append(categories[meta.Category], meta.Description)
		}

		for category, descs := range categories {
			fmt.Printf("\nCategory: %s\nPhotos: %d\nDescriptions:\n", category, len(descs))
			for _, d := range descs {
				fmt.Printf("- %s\n", d)
			}
		}
	},
}

func init() {
	addCmd.Flags().StringP("date", "d", "", "Photo date (required)")
	addCmd.Flags().StringP("category", "c", "", "Photo category (required)")
	addCmd.Flags().StringP("desc", "D", "", "Photo description (required)")
	addCmd.MarkFlagRequired("date")
	addCmd.MarkFlagRequired("category")
	addCmd.MarkFlagRequired("desc")

	rootCmd.AddCommand(initCmd, addCmd, reportCmd)
}

func main() {
	if err := rootCmd.Execute(); err != nil {
		log.Fatal(err)
	}
}
