use anyhow::Context;
use futures::future::join_all;

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    let (input_json, output_path) = (&args[1], &args[2]);

    let json_data = tokio::fs::read_to_string(input_json)
        .await
        .context("Failed to read JSON input")?;

    let file_paths: Vec<String> = serde_json::from_str(&json_data)
        .context("Invalid JSON format")?;

    let read_tasks = file_paths.into_iter().map(|path| {
        async {
            tokio::fs::read_to_string(&path)
                .await
                .map(|content| (path, content))
                .map_err(|e| (path, e))
        }
    });

    let mut concatenated = String::new();
    for result in join_all(read_tasks).await {
        match result {
            Ok((_, content)) => concatenated.push_str(&content),
            Err((path, error)) => eprintln!("Error reading {}: {}", path, error),
        }
    }

    tokio::fs::write(output_path, concatenated)
        .await
        .context("Failed to write output file")?;

    Ok(())
}
