	apiEndpoint := "https://api.example.com/users"
	filePath := "user.json"

	data, err := os.ReadFile(filePath)
	if err != nil {
		log.Fatalf("Error reading JSON file: %v", err)
	}

	var user User
	if err := json.Unmarshal(data, &user); err != nil {
		log.Fatalf("Error parsing JSON data: %v", err)
	}

	client := resty.New()
	resp, err := client.R().
		SetHeader("Content-Type", "application/json").
		SetBody(user).
		Post(apiEndpoint)

	if err != nil {
		log.Fatalf("Error sending POST request: %v", err)
	}

	if resp.IsSuccess() {
		fmt.Println("Successfully sent user data. Status code:", resp.StatusCode())
	} else {
		log.Printf("Request failed. Status code: %d, Response: %s", resp.StatusCode(), resp.String())
	}
}
