use tide::{Request, Response, StatusCode};
use serde::{Deserialize, Serialize};
use tide::prelude::*;
use thiserror::Error;

#[derive(Debug, Deserialize)]
struct ProductCodeRequest {
    codes: Vec<String>,
}

#[derive(Debug, Serialize)]
struct ProductCodeResponse {
    valid: Vec<String>,
    invalid: Vec<String>,
}

#[derive(Error, Debug)]
enum AppError {
    #[error("Invalid JSON format")]
    JsonParseError(#[from] serde_json::Error),
    #[error("Invalid request format")]
    RequestFormatError,
}

impl tide::convert::Into<Response> for AppError {
    fn into(self) -> Response {
        let status = match self {
            AppError::JsonParseError(_) => StatusCode::BadRequest,
            AppError::RequestFormatError => StatusCode::UnprocessableEntity,
        };
        Response::new(status).set_body(tide::Body::from_json(&self.to_string()).unwrap())
    }
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let mut app = tide::new();
    app.with(tide::log::LogMiddleware::new());

    app.at("/validate").post(validate_codes);
    app.listen("127.0.0.1:8080").await?;
    Ok(())
}

async fn validate_codes(mut req: Request<()>) -> tide::Result<Response> {
    let valid_codes = vec![
        "CODE123".to_string(),
        "CODE456".to_string(),
        "VALID99".to_string()
    ];

    let body: ProductCodeRequest = req.body_json().await.map_err(|e| AppError::JsonParseError(e))?;

    let (valid, invalid): (Vec<String>, Vec<String>) = body.codes.into_iter()
        .partition(|code| valid_codes.contains(code));

    Ok(Response::builder(StatusCode::Ok)
        .body(tide::Body::from_json(&ProductCodeResponse { valid, invalid })?)
        .build())
}
