        Ok(data) => Ok(Response::new(Body::from(data.to_string()))),
        Err(_) => Ok(Response::builder()
            .status(StatusCode::INTERNAL_SERVER_ERROR)
            .body(Body::from("Invalid JSON format"))
            .unwrap())
    }
}

