use serde::{Deserialize, Serialize};
use warp::{Filter, Rejection};

#[derive(Debug, Deserialize)]
struct SortRequest {
    data: Vec<i32>,
}

#[derive(Serialize)]
struct SortResponse {
    data: Vec<i32>,
}

#[derive(Debug)]
struct ServerError;
impl warp::reject::Reject for ServerError {}

async fn handle_sort(req: SortRequest) -> Result<impl warp::Reply, Rejection> {
    let data = req.data;
    let sorted_data = tokio::task::spawn_blocking(move || {
        let mut data = data;
        data.sort();
        data
    })
    .await
    .map_err(|_| warp::reject::custom(ServerError))?;
    Ok(warp::reply::json(&SortResponse { data: sorted_data }))
}

async fn handle_rejection(err: Rejection) -> Result<impl warp::Reply, std::convert::Infallible> {
    let (code, message) = if err.is::<warp::reject::InvalidBody>() {
        (warp::http::StatusCode::BAD_REQUEST, "Invalid JSON format")
    } else {
        (warp::http::StatusCode::INTERNAL_SERVER_ERROR, "Internal Server Error")
    };
    Ok(warp::reply::with_status(message, code))
}

#[tokio::main]
async fn main() {
    let sort_route = warp::path("sort")
        .and(warp::post())
        .and(warp::body::json())
        .and_then(handle_sort);

    warp::serve(sort_route.recover(handle_rejection))
        .run(([0, 0, 0, 0], 8080))
        .await;
}
