use futures_util::{SinkExt, StreamExt};
use std::{net::SocketAddr, sync::Arc};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::Mutex;
use tokio_tungstenite::tungstenite::protocol::Message;
use tokio_tungstenite::{accept_async, WebSocketStream};

async fn handle_connection(stream: WebSocketStream<TcpStream>, addr: SocketAddr) {
    let (mut ws_sender, mut ws_receiver) = stream.split();

    while let Some(msg) = ws_receiver.next().await {
        match msg {
            Ok(Message::Text(text)) => {
                if text == "END" {
                    let _ = ws_sender.send(Message::Close(None)).await;
                    break;
                }
                if let Err(e) = ws_sender.send(Message::Text(text)).await {
                    eprintln!("Error sending message to {}: {}", addr, e);
                    break;
                }
            }
            Ok(Message::Close(_)) => break,
            Err(e) => {
                eprintln!("Error receiving message from {}: {}", addr, e);
                break;
            }
            _ => {}
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    let listener = Arc::new(Mutex::new(listener));

    loop {
        let listener_clone = Arc::clone(&listener);
        let (stream, addr) = listener_clone.lock().await.accept().await?;

        tokio::spawn(async move {
            match accept_async(stream).await {
                Ok(ws_stream) => {
                    handle_connection(ws_stream, addr).await;
                }
                Err(e) => eprintln!("WebSocket handshake failed for {}: {}", addr, e),
            }
        });
    }
}
