import * as fs from 'fs/promises';
import * as E from 'fp-ts/Either';
import * as TE from 'fp-ts/TaskEither';
import { pipe } from 'fp-ts/function';

interface UserSettings {
  theme: string;
  notifications: boolean;
  language: string;
}

const validateUserSettings = (data: unknown): E.Either<string, UserSettings> => {
  if (
    typeof data === 'object' &&
    data !== null &&
    'theme' in data &&
    'notifications' in data &&
    'language' in data
  ) {
    return E.right(data as UserSettings);
  }
  return E.left('Invalid configuration structure');
};

const readConfigFile = (path: string): TE.TaskEither<string, UserSettings> =>
  pipe(
    TE.tryCatch(
      () => fs.readFile(path, 'utf-8'),
      (error) => `File read error: ${error}`
    ),
    TE.chain((content) =>
      pipe(
        E.parseJSON(content, (error) => `JSON parse error: ${error}`),
        E.chainW(validateUserSettings),
        TE.fromEither
      )
    )
  );

const writeConfigFile = (path: string, data: UserSettings): TE.TaskEither<string, void> =>
  TE.tryCatch(
    () => fs.writeFile(path, JSON.stringify(data, null, 2)),
    (error) => `File write error: ${error}`
  );

const updateUserConfig = (current: UserSettings, update: Partial<UserSettings>): UserSettings => ({
  ...current,
  ...update
});

const saveUpdatedConfig = (path: string, update: Partial<UserSettings>) =>
  pipe(
    readConfigFile(path),
    TE.map((config) => updateUserConfig(config, update)),
    TE.chainW((updatedConfig) => writeConfigFile(path, updatedConfig))
  );

// Example usage
pipe(
  saveUpdatedConfig('config.json', { theme: 'dark' }),
  TE.fold(
    (error) => TE.of(console.error(error)),
    () => TE.of(console.log('Settings updated successfully'))
  )
)();
