import * as t from 'io-ts';
import { pipe } from 'fp-ts/function';
import { fold, either } from 'fp-ts/Either';
import { DateFromISOString } from 'io-ts-types/lib/DateFromISOString';
import fetch from 'node-fetch';

const BlogPost = t.type({
  id: t.number,
  title: t.string,
  content: t.string,
  publishedDate: DateFromISOString,
});

type BlogPost = t.TypeOf<typeof BlogPost>;

const fetchBlogPosts = async (url: string): Promise<unknown> => {
  const response = await fetch(url);
  if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
  return response.json();
};

const validateBlogPosts = (data: unknown): either.Either<t.Errors, BlogPost[]> => {
  return t.array(BlogPost).decode(data);
};

const main = async () => {
  try {
    const apiUrl = 'https://api.example.com/blogposts';
    const data = await fetchBlogPosts(apiUrl);

    const result = validateBlogPosts(data);

    pipe(
      result,
      fold(
        (errors: t.Errors) => {
          console.error('Validation failed:');
          errors.forEach((err) => console.error(JSON.stringify(err)));
        },
        (posts: BlogPost[]) => {
          console.log('Validated blog posts:');
          posts.forEach((post) => {
            console.log(`Title: ${post.title}`);
            console.log(`Content: ${post.content}\n`);
          });
        }
      )
    );
  } catch (error) {
    if (error instanceof Error) {
      console.error(`Operation failed: ${error.message}`);
    } else {
      console.error('Unexpected error:', error);
    }
  }
};

main();
