```rust
// src/main.rs
#[macro_use]
extern crate diesel;

use anyhow::Result;
use clap::{Parser, Subcommand};
use diesel::prelude::*;
use diesel::sql_query;
use diesel_migrations::{embed_migrations, EmbeddedMigrations, MigrationHarness};
use std::env;

mod models;
mod schema;

pub const MIGRATIONS: EmbeddedMigrations = embed_migrations!();

#[derive(Parser)]
#[command(name = "bookstore")]
#[command(about = "Bookstore inventory management CLI", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Add a new book to inventory
    Add {
        #[arg(short, long)]
        title: String,
        #[arg(short, long)]
        author: String,
        #[arg(short, long)]
        year: i32,
        #[arg(short, long)]
        quantity: i32,
    },
    /// Update existing book details
    Update {
        #[arg(short, long)]
        id: i32,
        #[arg(short, long)]
        title: Option<String>,
        #[arg(short, long)]
        author: Option<String>,
        #[arg(short, long)]
        year: Option<i32>,
        #[arg(short, long)]
        quantity: Option<i32>,
    },
    /// Query books by criteria
    Query {
        #[arg(short, long)]
        id: Option<i32>,
        #[arg(short, long)]
        title: Option<String>,
        #[arg(short, long)]
        author: Option<String>,
    },
    /// Delete a book by ID
    Delete {
        #[arg(short, long)]
        id: i32,
    },
}

fn main() -> Result<()> {
    let connection = &mut establish_connection();
    connection.run_pending_migrations(MIGRATIONS)?;

    let args = Cli::parse();

    match args.command {
        Commands::Add {
            title,
            author,
            year,
            quantity,
        } => add_book(connection, &title, &author, year, quantity)?,
        Commands::Update {
            id,
            title,
            author,
            year,
            quantity,
        } => update_book(connection, id, title.as_deref(), author.as_deref(), year, quantity)?,
        Commands::Query { id, title, author } => query_books(connection, id, title, author)?,
        Commands::Delete { id } => delete_book(connection, id)?,
    }

    Ok(())
}

fn establish_connection() -> PgConnection {
    let database_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    PgConnection::establish(&database_url)
        .unwrap_or_else(|_| panic!("Error connecting to {}", database_url))
}

fn add_book(
    conn: &mut PgConnection,
    title: &str,
    author: &str,
    year: i32,
    quantity: i32,
) -> Result<()> {
    use schema::books::dsl::*;

    let new_book = models::NewBook {
        title,
        author,
        year,
        quantity,
    };

    diesel::insert_into(books)
        .values(&new_book)
        .execute(conn)?;

    println!("Book added successfully");
    Ok(())
}

fn update_book(
    conn: &mut PgConnection,
    book_id: i32,
    new_title: Option<&str>,
    new_author: Option<&str>,
    new_year: Option<i32>,
    new_quantity: Option<i32>,
) -> Result<()> {
    use schema::books::dsl::*;

    let mut query = books.find(book_id).first::<models::Book>(conn)?;

    if let Some(t) = new_title {
        query.title = t.to_string();
    }
    if let Some(a) = new_author {
        query.author = a.to_string();
    }
    if let Some(y) = new_year {
        query.year = y;
    }
    if let Some(q) = new_quantity {
        query.quantity = q;
    }

    diesel::update(books.find(book_id))
        .set((
            title.eq(query.title),
            author.eq(query.author),
            year.eq(query.year),
            quantity.eq(query.quantity),
        ))
        .execute(conn)?;

    println!("Book updated successfully");
    Ok(())
}

fn query_books(
    conn: &mut PgConnection,
    book_id: Option<i32>,
    search_title: Option<String>,
    search_author: Option<String>,
) -> Result<()> {
    use schema::books::dsl::*;

    let mut query = books.into_boxed();

    if let Some(id) = book_id {
        query = query.filter(id.eq(id));
    }
    if let Some(t) = search_title {
        query = query.filter(title.like(format!("%{}%", t)));
    }
    if let Some(a) = search_author {
        query = query.filter(author.like(format!("%{}%", a)));
    }

    let results = query.load::<models::Book>(conn)?;

    if results.is_empty() {
        println!("No books found matching criteria");
    } else {
        for book in results {
            println!(
                "ID: {}, Title: {}, Author: {}, Year: {}, Quantity: {}",
                book.id, book.title, book.author, book.year, book.quantity
            );
        }
    }
    Ok(())
}

fn delete_book(conn: &mut PgConnection, book_id: i32) -> Result<()> {
    use schema::books::dsl::*;

    let num_deleted = diesel::delete(books.find(book_id)).execute(conn)?;

    if num_deleted > 0 {
        println!("Book deleted successfully");
    } else {
        println!("No book found with ID {}", book_id);
    }
    Ok(())
}
