```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

type Book struct {
	ISBN      string `json:"isbn"`
	Title     string `json:"title"`
	Author    string `json:"author"`
	Stock     int    `json:"stock"`
}

var (
	books   []Book
	bookMap = make(map[string]int)
	mu      sync.Mutex
)

func main() {
	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(jsonMiddleware)

	r.Mount("/v1", v1Router())
	r.Mount("/v2", v2Router())

	log.Fatal(http.ListenAndServe(":8080", r))
}

func v1Router() chi.Router {
	r := chi.NewRouter()
	r.Route("/books", func(r chi.Router) {
		r.Get("/", listBooks)
		r.Post("/", createBook)
		r.Route("/{isbn}", func(r chi.Router) {
			r.Get("/", getBook)
			r.Put("/", updateBook)
			r.Delete("/", deleteBook)
		})
	})
	return r
}

func v2Router() chi.Router {
	r := chi.NewRouter()
	r.Route("/books", func(r chi.Router) {
		r.Get("/", listBooks)
		r.Post("/", createBook)
		r.Route("/{isbn}", func(r chi.Router) {
			r.Get("/", getBook)
			r.Put("/", updateBook)
			r.Delete("/", deleteBook)
		})
	})
	return r
}

func jsonMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		next.ServeHTTP(w, r)
	})
}

func listBooks(w http.ResponseWriter, r *http.Request) {
	mu.Lock()
	defer mu.Unlock()
	json.NewEncoder(w).Encode(books)
}

func getBook(w http.ResponseWriter, r *http.Request) {
	isbn := strings.ToLower(chi.URLParam(r, "isbn"))
	mu.Lock()
	defer mu.Unlock()

	index, exists := bookMap[isbn]
	if !exists {
		w.WriteHeader(http.StatusNotFound)
		json.NewEncoder(w).Encode(map[string]string{"error": "Book not found"})
		return
	}
	json.NewEncoder(w).Encode(books[index])
}

func createBook(w http.ResponseWriter, r *http.Request) {
	var book Book
	if err := json.NewDecoder(r.Body).Decode(&book); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(map[string]string{"error": "Invalid request body"})
		return
	}

	book.ISBN = strings.ToLower(book.ISBN)
	mu.Lock()
	defer mu.Unlock()

	if _, exists := bookMap[book.ISBN]; exists {
		w.WriteHeader(http.StatusConflict)
		json.NewEncoder(w).Encode(map[string]string{"error": "Book already exists"})
		return
	}

	books = append(books, book)
	bookMap[book.ISBN] = len(books) - 1
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(book)
}

func updateBook(w http.ResponseWriter, r *http.Request) {
	isbn := strings.ToLower(chi.URLParam(r, "isbn"))
	var update Book
	if err := json.NewDecoder(r.Body).Decode(&update); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(map[string]string{"error": "Invalid request body"})
		return
	}

	mu.Lock()
	defer mu.Unlock()

	index, exists := bookMap[isbn]
	if !exists {
		w.WriteHeader(http.StatusNotFound)
		json.NewEncoder(w).Encode(map[string]string{"error": "Book not found"})
		return
	}

	if update.Title != "" {
		books[index].Title = update.Title
	}
	if update.Author != "" {
		books[index].Author = update.Author
	}
	if update.Stock >= 0 {
		books[index].Stock = update.Stock
	}

	json.NewEncoder(w).Encode(books[index])
}

func deleteBook(w http.ResponseWriter, r *http.Request) {
	isbn := strings.ToLower(chi.URLParam(r, "isbn"))
	mu.Lock()
	defer mu.Unlock()

	index, exists := bookMap[isbn]
	if !exists {
		w.WriteHeader(http.StatusNotFound)
		json.NewEncoder(w).Encode(map[string]string{"error": "Book not found"})
		return
	}

	books = append(books[:index], books[index+1:]...)
	delete(bookMap, isbn)
	for i, book := range books[index:] {
		bookMap[book.ISBN] = index + i
	}

	w.WriteHeader(http.StatusNoContent)
}
