use async_std::{
    io::{BufReader, BufWriter},
    net::{TcpListener, TcpStream},
    prelude::*,
    task,
};
use std::sync::Arc;

#[async_std::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let listener = TcpListener::bind("127.0.0.1:8080").await?;
    println!("Server listening on port 8080");

    loop {
        let (stream, _) = listener.accept().await?;
        let stream = Arc::new(stream);
        task::spawn(handle_client(stream));
    }
}

async fn handle_client(stream: Arc<TcpStream>) {
    let peer_addr = match stream.peer_addr() {
        Ok(addr) => addr.to_string(),
        Err(_) => "unknown".into(),
    };
    println!("New connection from: {}", peer_addr);

    let stream = match stream.clone().try_unwrap() {
        Ok(s) => s,
        Err(_) => return,
    };

    let (reader, writer) = (stream.clone(), stream);
    let mut reader = BufReader::new(reader);
    let mut writer = BufWriter::new(writer);

    if let Err(e) = writer.write_all(b"Welcome to the server!\n").await {
        eprintln!("Error sending greeting to {}: {}", peer_addr, e);
        return;
    }
    if let Err(e) = writer.flush().await {
        eprintln!("Error flushing writer for {}: {}", peer_addr, e);
        return;
    }

    let mut line = String::new();
    loop {
        line.clear();
        match reader.read_line(&mut line).await {
            Ok(0) => break,
            Ok(_) => {
                let response = format!("Received: {}", line);
                if let Err(e) = writer.write_all(response.as_bytes()).await {
                    eprintln!("Error writing to {}: {}", peer_addr, e);
                    break;
                }
                if let Err(e) = writer.flush().await {
                    eprintln!("Error flushing writer for {}: {}", peer_addr, e);
                    break;
                }
            }
            Err(e) => {
                eprintln!("Error reading from {}: {}", peer_addr, e);
                break;
            }
        }
    }

    println!("Connection closed: {}", peer_addr);
}
