import { injectable, inject, container } from 'tsyringe';

class TaskExecutionError extends Error {
    constructor(public taskId: string, message: string) {
        super(message);
        this.name = 'TaskExecutionError';
    }
}

@injectable()
class TaskService {
    executeTask(taskId: string): Promise<string> {
        return new Promise((resolve, reject) => {
            if (!taskId || taskId.trim() === '') {
                const error = new TaskExecutionError(taskId, 'Invalid task ID');
                console.error(`[${new Date().toLocaleString()}] ${error.message}`);
                reject(error);
            } else {
                setTimeout(() => resolve(`Task ${taskId} executed`), 1000);
            }
        });
    }
}

@injectable()
class Scheduler {
    constructor(@inject(TaskService) private taskService: TaskService) {}

    async startTask(taskId: string): Promise<void> {
        const startTime = new Date().toLocaleString();
        console.log(`[${startTime}] Starting task ${taskId}`);

        try {
            await this.taskService.executeTask(taskId);
            console.log(`[${new Date().toLocaleString()}] Task ${taskId} completed`);
        } catch (error) {
            if (error instanceof TaskExecutionError) {
                console.error(`[${new Date().toLocaleString()}] Failed to execute task ${error.taskId}: ${error.message}`);
            } else {
                console.error(`[${new Date().toLocaleString()}] Unexpected error: ${error}`);
            }
        }
    }
}

