func createBook(ctx context.Context, client *ent.Client, title, author string, year int) (*ent.Book, error) {
    b, err := client.Book.
        Create().
        SetTitle(title).
        SetAuthor(author).
        SetPublicationYear(year).
        Save(ctx)
    if err != nil {
        return nil, err
    }
    return b, nil
}

func getBook(ctx context.Context, client *ent.Client, id int) (*ent.Book, error) {
    b, err := client.Book.Get(ctx, id)
    if err != nil {
        return nil, err
    }
    return b, nil
}

func updateBookYear(ctx context.Context, client *ent.Client, id, newYear int) error {
    _, err := client.Book.UpdateOneID(id).
        SetPublicationYear(newYear).
        Save(ctx)
    return err
}

func deleteBook(ctx context.Context, client *ent.Client, id int) error {
    return client.Book.DeleteOneID(id).Exec(ctx)
}

func getAllBooksByAuthor(ctx context.Context, client *ent.Client, author string) ([]*ent.Book, error) {
    books, err := client.Book.
        Query().
        Where(book.AuthorEQ(author)).
        All(ctx)
    if err != nil {
        return nil, err
    }
    return books, nil
}

