package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/urfave/cli/v2"
)

type Record struct {
	Name      string    `json:"name"`
	Timestamp time.Time `json:"timestamp"`
}

func main() {
	app := &cli.App{
		Flags: []cli.Flag{
			&cli.StringFlag{
				Name:     "dir",
				Usage:    "Directory containing JSON files",
				Required: true,
			},
			&cli.StringFlag{
				Name:  "time",
				Usage: "Optional time filter (RFC3339 format)",
			},
		},
		Action: func(c *cli.Context) error {
			dir := c.String("dir")
			timeFilterStr := c.String("time")

			var filterTime *time.Time
			if timeFilterStr != "" {
				parsed, err := time.Parse(time.RFC3339, timeFilterStr)
				if err != nil {
					return fmt.Errorf("invalid time format: %v", err)
				}
				filterTime = &parsed
			}

			files, err := ioutil.ReadDir(dir)
			if err != nil {
				return fmt.Errorf("error reading directory: %v", err)
			}

			var names []string
			for _, f := range files {
				if f.IsDir() || filepath.Ext(f.Name()) != ".json" {
					continue
				}

				path := filepath.Join(dir, f.Name())
				data, err := ioutil.ReadFile(path)
				if err != nil {
					return fmt.Errorf("error reading %s: %v", f.Name(), err)
				}

				var records []Record
				if err := json.Unmarshal(data, &records); err != nil {
					return fmt.Errorf("error parsing %s: %v", f.Name(), err)
				}

				for _, r := range records {
					if filterTime != nil && r.Timestamp.Before(*filterTime) {
						continue
					}
					names = append(names, r.Name)
				}
			}

			sort.Strings(names)
			for _, name := range names {
				fmt.Println(name)
			}
			return nil
		},
	}

	if err := app.Run(os.Args); err != nil {
		log.Fatal(err)
	}
}
