import { Body, Controller, Delete, Get, Path, Post, Put, Route, SuccessResponse, Query, Response, Tags } from 'tsoa';
import { Book, Author } from './models';
import { StatusCodes } from 'http-status-codes';

let books: Book[] = [];
let authors: Author[] = [];

@Route('books')
@Tags('Books')
export class BooksController extends Controller {
  @Get('/')
  async getAllBooks(@Query() title?: string): Promise<Book[]> {
    return title ? books.filter(b => b.title.includes(title)) : books;
  }

  @Get('{id}')
  @Response<{ message: string }>(StatusCodes.NOT_FOUND, 'Not Found')
  async getBook(@Path() id: string): Promise<Book> {
    const book = books.find(b => b.id === id);
    if (!book) {
      this.setStatus(StatusCodes.NOT_FOUND);
      throw new Error('Book not found');
    }
    return book;
  }

  @Post()
  @SuccessResponse(StatusCodes.CREATED)
  @Response<{ message: string }>(StatusCodes.BAD_REQUEST, 'Invalid input')
  async createBook(@Body() book: Book): Promise<void> {
    if (!authors.find(a => a.id === book.authorId)) {
      this.setStatus(StatusCodes.BAD_REQUEST);
      throw new Error('Author does not exist');
    }
    books.push(book);
    this.setStatus(StatusCodes.CREATED);
  }

  @Put('{id}')
  @Response<{ message: string }>(StatusCodes.NOT_FOUND, 'Not Found')
  async updateBook(@Path() id: string, @Body() updatedBook: Book): Promise<Book> {
    const index = books.findIndex(b => b.id === id);
    if (index === -1) {
      this.setStatus(StatusCodes.NOT_FOUND);
      throw new Error('Book not found');
    }
    books[index] = { ...books[index], ...updatedBook };
    return books[index];
  }

  @Delete('{id}')
  @SuccessResponse(StatusCodes.NO_CONTENT)
  @Response<{ message: string }>(StatusCodes.NOT_FOUND, 'Not Found')
  async deleteBook(@Path() id: string): Promise<void> {
    const index = books.findIndex(b => b.id === id);
    if (index === -1) {
      this.setStatus(StatusCodes.NOT_FOUND);
      throw new Error('Book not found');
    }
    books.splice(index, 1);
    this.setStatus(StatusCodes.NO_CONTENT);
  }
}

