package main

import (
	"fmt"
	"log"
	"os"
	"syscall"
	"time"

	"github.com/go-co-op/gocron"
)

func getDiskUsage() (float64, error) {
	var stat syscall.Statfs_t
	err := syscall.Statfs("/", &stat)
	if err != nil {
		return 0, err
	}
	total := stat.Blocks * uint64(stat.Bsize)
	free := stat.Bfree * uint64(stat.Bsize)
	used := total - free
	return (float64(used) / float64(total)) * 100, nil
}

func logUsage() {
	usage, err := getDiskUsage()
	if err != nil {
		log.Printf("Error checking disk usage: %v", err)
		return
	}

	logLine := fmt.Sprintf("[%s] Disk usage: %.2f%%\n", time.Now().Format(time.RFC3339), usage)
	file, err := os.OpenFile("disk_usage.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		log.Printf("Error opening log file: %v", err)
		return
	}
	defer file.Close()

	if _, err := file.WriteString(logLine); err != nil {
		log.Printf("Error writing to log file: %v", err)
	}
}

func main() {
	s := gocron.NewScheduler(time.UTC)
	_, err := s.Every(10).Minutes().Do(logUsage)
	if err != nil {
		log.Fatalf("Failed to schedule task: %v", err)
	}

	s.StartBlocking()
}
