use serde::{Deserialize, Serialize};
use std::fs::File;
use std::io::BufReader;
use std::path::Path;

#[derive(Debug, Serialize, Deserialize)]
struct Student {
    name: String,
    age: u8,
    gpa: f64,
}

#[derive(Serialize)]
struct AverageGPA {
    average_gpa: f64,
}

fn read_students(path: &Path) -> Result<Vec<Student>, Box<dyn std::error::Error>> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let students = serde_json::from_reader(reader)?;
    Ok(students)
}

fn calculate_average(students: &[Student]) -> Result<f64, Box<dyn std::error::Error>> {
    if students.is_empty() {
        return Err("No students provided".into());
    }
    let total: f64 = students.iter().map(|s| s.gpa).sum();
    Ok(total / students.len() as f64)
}

fn write_average(average: f64, path: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let file = File::create(path)?;
    let avg_gpa = AverageGPA { average_gpa: average };
    serde_json::to_writer_pretty(file, &avg_gpa)?;
    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let input_path = Path::new("students.json");
    let output_path = Path::new("average_gpa.json");

    let students = read_students(input_path)?;
    let average = calculate_average(&students)?;
    write_average(average, output_path)?;

    Ok(())
}
