// Cargo.toml
[package]
name = "auth_api"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = "0.6.20"
sqlx = { version = "0.7.2", features = ["postgres", "runtime-tokio", "macros"] }
tokio = { version = "1.0", features = ["full"] }
argon2 = "0.5.0"
serde = { version = "1.0", features = ["derive"] }
dotenv = "0.15.0"
bcrypt = "0.15.0"

// src/main.rs
use axum::{
    extract::Extension,
    http::StatusCode,
    response::IntoResponse,
    routing::post,
    Json, Router,
};
use serde::{Deserialize, Serialize};
use sqlx::postgres::PgPoolOptions;
use sqlx::PgPool;
use std::env;
use argon2::{
    password_hash::{
        rand_core::OsRng, PasswordHash, PasswordHasher, PasswordVerifier, SaltString
    },
    Argon2
};

#[derive(Debug)]
enum Error {
    DbError(sqlx::Error),
    HashError(argon2::password_hash::Error),
    AuthError,
}

impl IntoResponse for Error {
    fn into_response(self) -> axum::response::Response {
        match self {
            Error::DbError(_) => (StatusCode::INTERNAL_SERVER_ERROR, "Database error").into_response(),
            Error::HashError(_) => (StatusCode::INTERNAL_SERVER_ERROR, "Hashing error").into_response(),
            Error::AuthError => (StatusCode::UNAUTHORIZED, "Invalid credentials").into_response(),
        }
    }
}

impl From<sqlx::Error> for Error {
    fn from(err: sqlx::Error) -> Self {
        Error::DbError(err)
    }
}

impl From<argon2::password_hash::Error> for Error {
    fn from(err: argon2::password_hash::Error) -> Self {
        Error::HashError(err)
    }
}

#[derive(Deserialize)]
struct AuthRequest {
    username: String,
    password: String,
}

#[derive(Serialize)]
struct AuthResponse {
    message: String,
}

async fn register(
    Extension(pool): Extension<PgPool>,
    Json(credentials): Json<AuthRequest>,
) -> Result<impl IntoResponse, Error> {
    let salt = SaltString::generate(&mut OsRng);
    let argon2 = Argon2::default();
    let hash = argon2.hash_password(credentials.password.as_bytes(), &salt)?.to_string();

    sqlx::query!(
        "INSERT INTO users (username, password_hash) VALUES ($1, $2)",
        credentials.username,
        hash
    )
    .execute(&pool)
    .await?;

    Ok((StatusCode::CREATED, Json(AuthResponse { message: "User created".to_string() })))
}

async fn login(
    Extension(pool): Extension<PgPool>,
    Json(credentials): Json<AuthRequest>,
) -> Result<impl IntoResponse, Error> {
    let user = sqlx::query!(
        "SELECT password_hash FROM users WHERE username = $1",
        credentials.username
    )
    .fetch_optional(&pool)
    .await?
    .ok_or(Error::AuthError)?;

    let parsed_hash = PasswordHash::new(&user.password_hash)?;
    Argon2::default().verify_password(credentials.password.as_bytes(), &parsed_hash)
        .map_err(|_| Error::AuthError)?;

    Ok(Json(AuthResponse { message: "Login successful".to_string() }))
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    dotenv::dotenv().ok();
    let db_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let pool = PgPoolOptions::new().connect(&db_url).await?;

    sqlx::migrate!().run(&pool).await?;

    let app = Router::new()
        .route("/register", post(register))
        .route("/login", post(login))
        .layer(Extension(pool));

    axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .await?;

    Ok(())
}

