import asyncio
import aiohttp
from datetime import datetime

URLS = [
    "https://newsapi.org/v2/top-headlines?category=business&apiKey=YOUR_KEY",
    "https://financial.example.com/v3/articles?apikey=KEY"
]

async def fetch_url(session, url):
    try:
        async with session.get(url) as response:
            response.raise_for_status()
            return await response.json()
    except (aiohttp.ClientError, aiohttp.http_exceptions.HttpProcessingError) as e:
        print(f"Connection error for {url}: {str(e)}")
    except Exception as e:
        print(f"Unexpected error fetching {url}: {str(e)}")
    return None

def parse_timestamp(timestamp_str):
    try:
        return datetime.fromisoformat(timestamp_str.replace('Z', '+00:00'))
    except ValueError:
        return None

async def process_response(url, data):
    items = []
    if not data:
        return items
    try:
        if "newsapi.org" in url:
            for article in data.get("articles", []):
                headline = article.get("title")
                ts = parse_timestamp(article.get("publishedAt", ""))
                if headline and ts:
                    items.append({"headline": headline, "timestamp": ts})
        elif "financial.example.com" in url:
            for item in data.get("results", []):
                headline = item.get("content", {}).get("title")
                ts = parse_timestamp(item.get("publishedTime"))
                if headline and ts:
                    items.append({"headline": headline, "timestamp": ts})
    except (KeyError, TypeError) as e:
        print(f"Data parsing error for {url}: {str(e)}")
    return items

async def main():
    async with aiohttp.ClientSession() as session:
        tasks = [fetch_url(session, url) for url in URLS]
        responses = await asyncio.gather(*tasks)
        processed = await asyncio.gather(*[process_response(url, data) for url, data in zip(URLS, responses)])
        all_items = [item for sublist in processed for item in sublist]
        sorted_items = sorted(all_items, key=lambda x: x["timestamp"])
        for entry in sorted_items:
            print(f"{entry['timestamp'].isoformat()}: {entry['headline']}")

if __name__ == "__main__":
    asyncio.run(main())
