package main

import (
	"errors"

	log "github.com/sirupsen/logrus"
	"gorm.io/gorm"
)

func AddBook(db *gorm.DB, title, author, isbn string, quantity uint) error {
	log.WithFields(log.Fields{
		"title":    title,
		"author":   author,
		"isbn":     isbn,
		"quantity": quantity,
	}).Info("Adding new book")

	book := Book{Title: title, Author: author, ISBN: isbn, Quantity: quantity}
	result := db.Create(&book)
	if result.Error != nil {
		log.WithError(result.Error).Error("Failed to add book")
		return result.Error
	}
	return nil
}

func UpdateBook(db *gorm.DB, isbn string, title, author string, quantity uint) error {
	log.WithFields(log.Fields{"isbn": isbn}).Info("Updating book")

	var book Book
	result := db.Where("isbn = ?", isbn).First(&book)
	if result.Error != nil {
		log.WithError(result.Error).Error("Book not found")
		return result.Error
	}

	updates := Book{Title: title, Author: author, Quantity: quantity}
	result = db.Model(&book).Updates(updates)
	if result.Error != nil {
		log.WithError(result.Error).Error("Failed to update book")
		return result.Error
	}
	return nil
}

func DeleteBook(db *gorm.DB, isbn string) error {
	log.WithFields(log.Fields{"isbn": isbn}).Info("Deleting book")

	result := db.Where("isbn = ?", isbn).Delete(&Book{})
	if result.Error != nil {
		log.WithError(result.Error).Error("Failed to delete book")
		return result.Error
	}
	if result.RowsAffected == 0 {
		err := errors.New("no book found with given ISBN")
		log.WithError(err).Error("Delete operation failed")
		return err
	}
	return nil
}

func GetBook(db *gorm.DB, isbn string) (Book, error) {
	log.WithFields(log.Fields{"isbn": isbn}).Info("Fetching book")

	var book Book
	result := db.Where("isbn = ?", isbn).First(&book)
	if result.Error != nil {
		log.WithError(result.Error).Error("Book not found")
		return Book{}, result.Error
	}
	return book, nil
}

func GetAllBooks(db *gorm.DB) ([]Book, error) {
	log.Info("Fetching all books")

	var books []Book
	result := db.Find(&books)
	if result.Error != nil {
		log.WithError(result.Error).Error("Failed to fetch books")
		return nil, result.Error
	}
	return books, nil
}
