```go
package main

import (
	"encoding/csv"
	"fmt"
	"io"
	"os"
	"strconv"
	"time"

	"github.com/AsynkronIT/protoactor-go/actor"
)

type TradeData struct {
	FirmID     string
	StockSymbol string
	Price      float64
	Volume     int
}

type GatherStats struct{}
type FirmStats struct {
	TotalVolume int
	MaxPrice    float64
}
type Finish struct{}

type Aggregator struct {
	firms        map[string]*actor.PID
	totalVolume  int
	maxPrice     float64
	pendingFirms int
}

func (a *Aggregator) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case *TradeData:
		pid, exists := a.firms[msg.FirmID]
		if !exists {
			props := actor.PropsFromProducer(func() actor.Actor { return &FirmActor{} })
			pid = ctx.Spawn(props)
			a.firms[msg.FirmID] = pid
		}
		ctx.Send(pid, msg)
	case *Finish:
		a.pendingFirms = len(a.firms)
		if a.pendingFirms == 0 {
			fmt.Println("No trading data processed")
			return
		}
		a.totalVolume = 0
		a.maxPrice = 0
		for _, pid := range a.firms {
			ctx.Request(pid, &GatherStats{})
		}
	case *FirmStats:
		a.totalVolume += msg.TotalVolume
		if msg.MaxPrice > a.maxPrice {
			a.maxPrice = msg.MaxPrice
		}
		a.pendingFirms--
		if a.pendingFirms == 0 {
			fmt.Printf("Total Trading Volume: %d\n", a.totalVolume)
			fmt.Printf("Highest Stock Price: %.2f\n", a.maxPrice)
		}
	}
}

type FirmActor struct {
	totalVolume int
	maxPrice    float64
}

func (f *FirmActor) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case *TradeData:
		f.totalVolume += msg.Volume
		if msg.Price > f.maxPrice {
			f.maxPrice = msg.Price
		}
	case *GatherStats:
		ctx.Respond(&FirmStats{
			TotalVolume: f.totalVolume,
			MaxPrice:    f.maxPrice,
		})
	}
}

func main() {
	system := actor.NewActorSystem()
	rootContext := system.Root

	aggProps := actor.PropsFromProducer(func() actor.Actor { return &Aggregator{firms: make(map[string]*actor.PID)} })
	aggPid := rootContext.Spawn(aggProps)

	file, err := os.Open("trades.csv")
	if err != nil {
		panic(err)
	}
	defer file.Close()

	reader := csv.NewReader(file)
	reader.FieldsPerRecord = 4

	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			fmt.Printf("CSV read error: %v\n", err)
			continue
		}
		if len(record) != 4 {
			fmt.Printf("Invalid record: %v\n", record)
			continue
		}

		price, err := strconv.ParseFloat(record[2], 64)
		if err != nil {
			fmt.Printf("Invalid price in %v: %v\n", record, err)
			continue
		}
		volume, err := strconv.Atoi(record[3])
		if err != nil {
			fmt.Printf("Invalid volume in %v: %v\n", record, err)
			continue
		}

		rootContext.Send(aggPid, &TradeData{
			FirmID:     record[0],
			StockSymbol: record[1],
			Price:      price,
			Volume:     volume,
		})
	}

	rootContext.Send(aggPid, &Finish{})
	time.Sleep(3 * time.Second)
}
