import httpx
import csv
import asyncio
import os

API_KEY = os.getenv('NEWS_API_KEY')
if not API_KEY:
    raise ValueError("NEWS_API_KEY environment variable not set.")

def read_countries(filename):
    countries = []
    try:
        with open(filename, 'r') as csvfile:
            reader = csv.DictReader(csvfile)
            required = ['country name', 'minimum article count']
            if not all(col in reader.fieldnames for col in required):
                raise ValueError("CSV missing required columns.")
            for row in reader:
                try:
                    code = row['country name'].strip()
                    min_art = int(row['minimum article count'])
                    countries.append((code, min_art))
                except (KeyError, ValueError) as e:
                    print(f"Skipping row {reader.line_num}: {str(e)}")
    except FileNotFoundError:
        print(f"File {filename} not found.")
    except Exception as e:
        print(f"Error: {str(e)}")
    return countries

async def fetch_articles(session, code, min_art):
    url = 'https://newsapi.org/v2/top-headlines'
    params = {'country': code, 'apiKey': API_KEY, 'pageSize': 100}
    try:
        resp = await session.get(url, params=params)
        resp.raise_for_status()
        total = resp.json().get('totalResults', 0)
        return (code, total if total >= min_art else 0)
    except Exception as e:
        print(f"Error for {code}: {str(e)}")
        return (code, 0)

async def main(filename):
    countries = read_countries(filename)
    if not countries:
        return
    async with httpx.AsyncClient() as client:
        tasks = [fetch_articles(client, c, m) for c, m in countries]
        results = await asyncio.gather(*tasks)
    print("Country\tQualifying Articles")
    for country, count in results:
        print(f"{country}\t{count}")

if __name__ == "__main__":
    import sys
    if len(sys.argv) != 2:
        print("Usage: python script.py <filename.csv>")
        sys.exit(1)
    asyncio.run(main(sys.argv[1]))
