import axios from 'axios';
import { match, P } from 'ts-pattern';

async function fetchCharacter(id: number): Promise<void> {
  try {
    const response = await axios.get(`https://swapi.dev/api/people/${id}/`);

    const characterData = match(response.data)
      .with(
        {
          name: P.string,
          gender: P.string,
          species: P.array(P.string),
        },
        ({ name, gender, species }) => ({ name, gender, species })
      )
      .with(
        {
          name: P.string,
          gender: P.string,
        },
        ({ name, gender }) => ({ name, gender, species: [] })
      )
      .with(
        {
          name: P.string,
        },
        ({ name }) => ({ name, gender: 'Unknown', species: [] })
      )
      .otherwise(() => {
        throw new Error('Unexpected response schema');
      });

    console.log(JSON.stringify({
      ...characterData,
      species: characterData.species.join(', ') || 'Unknown',
    }, null, 2));
  } catch (error) {
    match(error)
      .with({ response: { status: P.number } }, (err) => {
        console.error(`API Error: ${err.response.status}`);
      })
      .with({ message: P.string }, (err) => {
        console.error(`Network Error: ${err.message}`);
      })
      .otherwise(() => {
        console.error('Unknown error occurred');
      });
  }
}

