package main

import (
	"golang.org/x/exp/constraints"
	"sync"
)

type Numeric interface {
	constraints.Integer | constraints.Float
}

func ConcurrentSum[T Numeric](nums []T) T {
	var total T
	var wg sync.WaitGroup
	var mu sync.Mutex

	mid := len(nums) / 2
	parts := [][]T{nums[:mid], nums[mid:]}

	wg.Add(len(parts))
	for _, part := range parts {
		go func(p []T) {
			defer wg.Done()
			sum := T(0)
			for _, n := range p {
				sum += n
			}
			mu.Lock()
			total += sum
			mu.Unlock()
		}(part)
	}

	wg.Wait()
	return total
}
