```python
import requests
import logging
import json
import os
import sys
import time

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[logging.StreamHandler()]
)
logger = logging.getLogger(__name__)

API_ENDPOINT = os.getenv('WEATHER_API_ENDPOINT')
if not API_ENDPOINT:
    logger.error("API endpoint not configured")
    raise ValueError("Missing WEATHER_API_ENDPOINT environment variable")

class WeatherClient:
    def __init__(self, endpoint=API_ENDPOINT, max_retries=3):
        self.endpoint = endpoint
        self.max_retries = max_retries
        self.session = requests.Session()

    def fetch_weather(self, location):
        for attempt in range(self.max_retries):
            try:
                url = f"{self.endpoint.rstrip('/')}/{location}"
                logger.info(f"Requesting weather data from {url}")
                response = self.session.get(url, timeout=10)
                response.raise_for_status()
                return self.parse_weather_data(response.json())
            except requests.exceptions.HTTPError as e:
                logger.error(f"HTTP error: {e}")
                if e.response.status_code == 404:
                    break
            except (requests.exceptions.ConnectionError, requests.exceptions.Timeout) as e:
                logger.warning(f"Connection error: {e}. Retry {attempt + 1}/{self.max_retries}")
                time.sleep(2)
            except json.JSONDecodeError as e:
                logger.error(f"Invalid JSON response: {e}")
                break
        return None

    def parse_weather_data(self, data):
        try:
            temperature = data['main']['temp']
            humidity = data['main']['humidity']
            conditions = data['weather'][0]['description']
            return self.format_weather_output(temperature, humidity, conditions)
        except KeyError as e:
            logger.error(f"Missing data key in response: {e}")
            return None

    @staticmethod
    def format_weather_output(temp, humidity, conditions):
        return (
            f"Current Weather:\n"
            f"Temperature: {temp}°C\n"
            f"Humidity: {humidity}%\n"
            f"Conditions: {conditions.title()}"
        )

if __name__ == "__main__":
    if sys.version_info < (3, 6):
        logger.error("Requires Python 3.6+")
        sys.exit(1)

    client = WeatherClient()
    weather = client.fetch_weather("London")
    print(weather if weather else "Failed to retrieve weather data")
